SELECT 
    TRUNC(TGL_MASUK) AS TANGGAL,
    COUNT(NO_PERMOHONAN) AS INFLOW_MASUK,
    SUM(CASE WHEN UPPER(KATEGORI_STATUS) = 'TERBIT' THEN 1 ELSE 0 END) AS OUTFLOW_TERBIT
FROM US_DWH.BI_T_ALL
WHERE TGL_MASUK IS NOT NULL
  AND {rentang_tgl_masuk}
  AND {pilih_izin}
  AND {filter_tahun}
  AND {filter_bulan}
GROUP BY TRUNC(TGL_MASUK)
ORDER BY TRUNC(TGL_MASUK) ASC

SELECT 
    COALESCE(
        ROUND(
            SUM(CASE WHEN KATEGORI_STATUS <> 'DALAM PROSES' THEN 1 ELSE 0 END) 
            / NULLIF(COUNT(NO_PERMOHONAN), 0), 
        4), 
    0) AS PERFORMA_PENYELESAIAN
FROM US_DWH.BI_T_ALL
WHERE 1=1
  AND {pilih_izin}
  AND {filter_tahun}
  AND {filter_bulan}
  AND {rentang_tgl_masuk}

SELECT 
    COUNT(NO_PERMOHONAN) AS TOTAL_DOKUMEN,
    COALESCE(SUM(CASE WHEN KATEGORI_STATUS = 'TERBIT' THEN 1 ELSE 0 END), 0) AS TOTAL_TERBIT,
    COALESCE(SUM(CASE WHEN KATEGORI_STATUS = 'TOLAK' THEN 1 ELSE 0 END), 0) AS TOTAL_TOLAK,
    COALESCE(SUM(CASE WHEN KATEGORI_STATUS = 'PROSES PELAKU USAHA' THEN 1 ELSE 0 END), 0) AS TOTAL_PELAKU_USAHA,
    COALESCE(SUM(CASE WHEN KATEGORI_STATUS = 'DALAM PROSES' THEN 1 ELSE 0 END), 0) AS TOTAL_DALAM_PROSES,
    COALESCE(SUM(CASE WHEN KATEGORI_STATUS = 'DALAM PROSES' AND HARI_SLA_TERPAKAI > BATAS_SLA_HARI THEN 1 ELSE 0 END), 0) AS TOTAL_MELEWATI_SLA
FROM US_DWH.BI_T_IZIN_OSS
WHERE 1=1
  AND {pilih_izin}
  AND {filter_tahun}
  AND {filter_bulan}
  AND {rentang_tgl_masuk}

SELECT 
    COALESCE(
        ROUND(
            SUM(CASE WHEN KATEGORI_STATUS <> 'DALAM PROSES' THEN 1 ELSE 0 END) 
            / NULLIF(COUNT(NO_PERMOHONAN), 0), 
        4), 
    0) AS PERFORMA_PENYELESAIAN
FROM US_DWH.BI_T_IZIN_OSS
WHERE 1=1
  AND {pilih_izin}
  AND {filter_tahun}
  AND {filter_bulan}
  AND {rentang_tgl_masuk}

WITH FILTERED_DATA AS (
    SELECT RISIKO, NO_PERMOHONAN
    FROM US_DWH.BI_T_IZIN_OSS
    WHERE 1=1
      AND {pilih_izin}
      AND {filter_tahun}
      AND {filter_bulan}
      AND {rentang_tgl_masuk}
)
SELECT 
    UPPER(RISIKO) AS TINGKAT_RISIKO,
    COALESCE(COUNT(NO_PERMOHONAN), 0) AS JUMLAH_DOKUMEN
FROM FILTERED_DATA
WHERE RISIKO IS NOT NULL
GROUP BY UPPER(RISIKO)
ORDER BY JUMLAH_DOKUMEN DESC

SELECT 
    COALESCE(
        ROUND(
            SUM(CASE WHEN HARI_SLA_TERPAKAI <= BATAS_SLA_HARI THEN 1 ELSE 0 END) 
            / NULLIF(COUNT(NO_PERMOHONAN), 0), 
        4), 
    0) AS KEPATUHAN_SLA
FROM US_DWH.BI_T_IZIN_OSS
WHERE KATEGORI_STATUS <> 'PROSES PELAKU USAHA'
  AND {pilih_izin}
  AND {filter_tahun}
  AND {filter_bulan}
  AND {rentang_tgl_masuk}

SELECT 
    COUNT(TX_PERMOHONAN.SEQREQ) AS TOTAL_PERMOHONAN,
    COUNT(CASE WHEN TX_PERMOHONAN.STATUS_IZIN = '02030188' THEN 1 END) AS TOTAL_TERBIT,
    COUNT(CASE WHEN TX_PERMOHONAN.STATUS_IZIN = '02030199' THEN 1 END) AS TOTAL_TOLAK,
    COUNT(CASE WHEN TX_PERMOHONAN.STATUS_IZIN = '02030190' THEN 1 END) AS TOTAL_CABUT,
    COUNT(CASE WHEN TX_PERMOHONAN.STATUS_IZIN NOT IN ('02030188', '02030199', '02030190') THEN 1 END) AS TOTAL_PROSES
FROM US_OSS.TX_PERMOHONAN
LEFT JOIN US_OSS.TM_LAYAN LYN ON TX_PERMOHONAN.IDLAYAN = LYN.IDLAYAN
LEFT JOIN US_OSS.TM_ROLE R ON TX_PERMOHONAN.STATUS_IZIN = R.KD_ROLE
WHERE TX_PERMOHONAN.STATUSINVOICE = 1
  AND {rentang_waktu}
  AND {pilih_tahun}
  AND {pilih_bulan}
  AND {pilih_role}
  AND {pilih_izin_iboss}

SELECT 
    SUM(CASE WHEN TX_PERMOHONAN.STATUS_IZIN IN ('02030188', '02030199', '02030190') THEN 1 ELSE 0 END) 
    / NULLIF(COUNT(TX_PERMOHONAN.SEQREQ), 0) AS GAUGE_PERFORMA
FROM US_OSS.TX_PERMOHONAN
LEFT JOIN US_OSS.TM_LAYAN LYN ON TX_PERMOHONAN.IDLAYAN = LYN.IDLAYAN
LEFT JOIN US_OSS.TM_ROLE R ON TX_PERMOHONAN.STATUS_IZIN = R.KD_ROLE
WHERE TX_PERMOHONAN.STATUSINVOICE = 1
  AND {rentang_waktu}
  AND {pilih_tahun}
  AND {pilih_bulan}
  AND {pilih_role}
  AND {pilih_izin_iboss}
